import{_ as a,c as i,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Histórico de Versões | Agent Skills","description":"Ver o histórico de atualizações de versão e mudanças de funcionalidades do projeto Agent Skills.","frontmatter":{"title":"Histórico de Versões | Agent Skills","sidebarTitle":"Versões","subtitle":"Histórico de Versões","description":"Ver o histórico de atualizações de versão e mudanças de funcionalidades do projeto Agent Skills.","tags":["changelog","updates","releases"]},"headers":[],"relativePath":"pt/vercel-labs/agent-skills/changelog/releases/index.md","filePath":"pt/vercel-labs/agent-skills/changelog/releases/index.md"}'),s={name:"pt/vercel-labs/agent-skills/changelog/releases/index.md"};function t(l,e,d,n,c,m){return o(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="historico-de-versoes" tabindex="-1">Histórico de Versões <a class="header-anchor" href="#historico-de-versoes" aria-label="Permalink to &quot;Histórico de Versões&quot;">​</a></h1><p>Este projeto registra todas as atualações, melhorias e correções de cada versão.</p><hr><h2 id="v1-0-0-janeiro-de-2026" tabindex="-1">v1.0.0 - Janeiro de 2026 <a class="header-anchor" href="#v1-0-0-janeiro-de-2026" aria-label="Permalink to &quot;v1.0.0 - Janeiro de 2026&quot;">​</a></h2><h3 id="🎉-lancamento-inicial" tabindex="-1">🎉 Lançamento Inicial <a class="header-anchor" href="#🎉-lancamento-inicial" aria-label="Permalink to &quot;🎉 Lançamento Inicial&quot;">​</a></h3><p>Esta é a primeira versão oficial do Agent Skills, contendo pacotes de habilidades completos e cadeia de ferramentas de build.</p><h4 id="novas-funcionalidades" tabindex="-1">Novas Funcionalidades <a class="header-anchor" href="#novas-funcionalidades" aria-label="Permalink to &quot;Novas Funcionalidades&quot;">​</a></h4><p><strong>Regras de Otimização de Desempenho do React</strong></p><ul><li>Mais de 40 regras de otimização de desempenho para React/Next.js</li><li>8 categorias principais: eliminando cachoeiras, otimização de empacotamento, desempenho no servidor, otimização de re-render, etc.</li><li>Classificado por nível de impacto (CRITICAL &gt; HIGH &gt; MEDIUM &gt; LOW)</li><li>Cada regra inclui exemplos comparativos de código Incorreto/Correto</li></ul><p><strong>Deploy com Um Clique no Vercel</strong></p><ul><li>Suporte para detecção automática de mais de 40 frameworks principais</li><li>Processo de deploy sem autenticação</li><li>Geração automática de links de preview e de transferência de propriedade</li><li>Suporte para projetos HTML estáticos</li></ul><p><strong>Diretrizes de Design da Web</strong></p><ul><li>Mais de 100 regras de design de interface web</li><li>Auditoria multidimensional acessibilidade, desempenho, UX</li><li>Busca remota das regras mais recentes (do GitHub)</li></ul><p><strong>Cadeia de Ferramentas de Build</strong></p><ul><li><code>pnpm build</code> - Gera documentação completa AGENTS.md</li><li><code>pnpm validate</code> - Valida integridade de arquivos de regras</li><li><code>pnpm extract-tests</code> - Extrai casos de teste</li><li><code>pnpm dev</code> - Fluxo de desenvolvimento (build + validate)</li></ul><h4 id="stack-tecnologico" tabindex="-1">Stack Tecnológico <a class="header-anchor" href="#stack-tecnologico" aria-label="Permalink to &quot;Stack Tecnológico&quot;">​</a></h4><ul><li>TypeScript 5.3.0</li><li>Node.js 20+</li><li>pnpm 10.24.0+</li><li>tsx 4.7.0 (runtime TypeScript)</li></ul><h4 id="documentacao" tabindex="-1">Documentação <a class="header-anchor" href="#documentacao" aria-label="Permalink to &quot;Documentação&quot;">​</a></h4><ul><li>Guia completo de regras AGENTS.md</li><li>Arquivo de definição de habilidades SKILL.md</li><li>README.md com instruções de instalação e uso</li><li>Documentação completa da cadeia de ferramentas</li></ul><hr><h2 id="convencoes-de-nomenclatura-de-versao" tabindex="-1">Convenções de Nomenclatura de Versão <a class="header-anchor" href="#convencoes-de-nomenclatura-de-versao" aria-label="Permalink to &quot;Convenções de Nomenclatura de Versão&quot;">​</a></h2><p>O projeto segue Controle de Versão Semântico (Semantic Versioning):</p><ul><li><strong>Número Major</strong>: Mudanças incompatíveis na API</li><li><strong>Número Minor</strong>: Novas funcionalidades compatíveis retroativamente</li><li><strong>Número Patch</strong>: Correções de bugs compatíveis retroativamente</li></ul><p>Exemplo: <code>1.0.0</code> indica a primeira versão estável.</p>',24)])])}const h=a(s,[["render",t]]);export{u as __pageData,h as default};
